import bisect

class Solution(object):
    def longestSubsequence(self, nums):
        best = 0
        for bit in range(30):
            # Filter elements with this bit set
            filtered = [x for x in nums if x & (1 << bit)]
            if not filtered:
                continue
            # LIS on filtered
            tails = []
            for v in filtered:
                pos = bisect.bisect_left(tails, v)
                if pos == len(tails):
                    tails.append(v)
                else:
                    tails[pos] = v
            best = max(best, len(tails))
        return best
